def calculate_shipping(weight, destination, is_express, is_fragile):
    if destination == 'domestic':
        if weight <= 1:
            base_cost = 5.99
        elif weight <= 5:
            base_cost = 9.99
        elif weight <= 10:
            base_cost = 14.99
        elif weight <= 25:
            base_cost = 19.99
        else:
            base_cost = 29.99
        if is_express:
            if weight <= 1:
                base_cost = 5.99 * 2
            elif weight <= 5:
                base_cost = 9.99 * 2
            elif weight <= 10:
                base_cost = 14.99 * 2
            elif weight <= 25:
                base_cost = 19.99 * 2
            else:
                base_cost = 29.99 * 2
        if is_fragile:
            base_cost = base_cost + 4.99
        tax = base_cost * 0.08
        total = base_cost + tax
        return total
    elif destination == 'international':
        if weight <= 1:
            base_cost = 15.99
        elif weight <= 5:
            base_cost = 24.99
        elif weight <= 10:
            base_cost = 39.99
        elif weight <= 25:
            base_cost = 59.99
        else:
            base_cost = 89.99
        if is_express:
            if weight <= 1:
                base_cost = 15.99 * 2.5
            elif weight <= 5:
                base_cost = 24.99 * 2.5
            elif weight <= 10:
                base_cost = 39.99 * 2.5
            elif weight <= 25:
                base_cost = 59.99 * 2.5
            else:
                base_cost = 89.99 * 2.5
        if is_fragile:
            base_cost = base_cost + 9.99
        tax = base_cost * 0.0
        total = base_cost + tax
        return total
    else:
        return -1
